# ====== core/utils.py ======
"""通用工具：均线角度、乖离率、阳线比例 + 全部纯计算指标函数"""

import math
import numpy as np
import pandas as pd


# ============================================================
#  原有函数（保留，测试依赖）
# ============================================================

def calc_ma_angle(ma_values, window=5):
    """计算均线角度（度），返回 0-90 的 float

    使用 arctan 计算均线最近 window 个点的斜率角度。
    angle = arctan(abs(diff) / (window-1) / v0 * 100)
    """
    if len(ma_values) < window or window < 2:
        return 0.0
    recent = ma_values[-window:]
    diff = recent[-1] - recent[0]
    if recent[0] == 0:
        return 0.0
    angle_rad = math.atan(abs(diff) / (window - 1) / recent[0] * 100)
    angle_deg = math.degrees(angle_rad)
    return min(angle_deg, 90.0)


def calc_bias(price, ma):
    """计算乖离率（百分比）

    bias = (price - ma) / ma * 100
    """
    if ma == 0:
        return 0.0
    return (float(price) - float(ma)) / float(ma) * 100


def calc_up_ratio(closes, period=20):
    """计算阳线比例（0-1）

    阳线定义为收盘价高于前一根收盘价。
    up_ratio = 上涨天数 / 周期
    """
    if len(closes) < 2 or period < 1:
        return 0.0
    n = min(period, len(closes) - 1)
    if n <= 0:
        return 0.0
    up_count = 0
    for i in range(-n, 0):
        if closes[i] >= closes[i - 1]:
            up_count += 1
    return up_count / n


# ============================================================
#  技术指标
# ============================================================

def calc_kdj(close, high, low, n=9, m1=3, m2=3):
    """
    计算 KDJ 指标。
    返回 (k_series, d_series, j_series)，长度与输入一致。
    """
    L = low.rolling(n).min()
    H = high.rolling(n).max()
    rsv = (close - L) / (H - L) * 100
    rsv = rsv.fillna(50)

    k = rsv.ewm(alpha=1/m1, adjust=False).mean()
    d = k.ewm(alpha=1/m2, adjust=False).mean()
    j = 3 * k - 2 * d

    k = k.fillna(50)
    d = d.fillna(50)
    j = j.fillna(50)
    return k, d, j


def calc_atr(close, high, low, n=14):
    """
    计算真实波幅 ATR。
    标准算法: max(|H-L|, |H-prevC|, |L-prevC|) 的 n 日 EMA。
    """
    prev_close = close.shift(1)
    tr1 = high - low
    tr2 = (high - prev_close).abs()
    tr3 = (low - prev_close).abs()
    tr = pd.concat([tr1, tr2, tr3], axis=1).max(axis=1)
    atr = tr.ewm(span=n, adjust=False).mean()
    return atr


def calc_volume_ratio(volume, vol_ma_period=5):
    """计算当日成交量 / 均量，返回比值序列。"""
    vol_ma = volume.rolling(vol_ma_period).mean()
    return volume / vol_ma.replace(0, np.nan)


def detect_long_upper_shadow(high, close, open_, shadow_ratio=0.5):
    """
    检测长上影线。
    上影线长度 = (最高 - 最大值(收盘, 开盘))
    上影线比例 = 上影线 / (最高 - 最低)
    返回布尔序列。
    """
    candle_high = high
    candle_body_top = pd.concat([close, open_], axis=1).max(axis=1)
    upper_shadow = candle_high - candle_body_top
    total_range = high - pd.concat([close, open_], axis=1).min(axis=1)
    total_range = total_range.replace(0, np.nan)
    ratio = upper_shadow / total_range
    return ratio.fillna(0) >= shadow_ratio


def detect_volume_price_divergence(close, volume, lookback=5, volume_diverge_threshold=0.70):
    """
    检测量价背离：价格创 lookback 日新高，但成交量较前日萎缩。
    返回 (是否背离, 量缩比例)。
    """
    if len(close) < 2:
        return False, 0.0
    price_high = close.iloc[-1] >= close.iloc[-lookback:].max()
    if not price_high:
        return False, 0.0
    vol_ratio = volume.iloc[-1] / volume.iloc[-2] if volume.iloc[-2] > 0 else 1
    if vol_ratio < volume_diverge_threshold:
        return True, float(vol_ratio)
    return False, float(vol_ratio)


def detect_last_3_negative_vol(close, open_, lookback_days=3):
    """
    检测最近 N 日是否连续缩量收阴（用于 B3 高位天量收阴后确认）。
    返回 bool。
    """
    if len(close) < lookback_days:
        return False
    recent = close.iloc[-lookback_days:]
    recent_o = open_.iloc[-lookback_days:]
    negative_days = (recent < recent_o).sum()
    return negative_days >= 2


# ============================================================
#  均线角度（独立函数，与类内方法同名）
# ============================================================

def calc_angle_simple(ma_series):
    """计算均线角度（度），返回最后一根的值。"""
    if len(ma_series) < 3:
        return None
    try:
        prev = float(ma_series.iloc[-2])
        curr = float(ma_series.iloc[-1])
        if prev <= 0:
            return None
        pct_change = (curr - prev) / prev
        rad = np.arctan(pct_change * 100)
        deg = float(rad * 180 / np.pi)
        return deg
    except Exception:
        return None


def trading_days_between(date1_str, date2_str, df):
    """计算两个日期之间的交易日数（基于 DataFrame 索引）。"""
    try:
        dates = pd.to_datetime(df.index)
        d1 = pd.Timestamp(date1_str)
        d2 = pd.Timestamp(date2_str)
        return len(dates[(dates > d1) & (dates <= d2)])
    except Exception:
        return 999


# ============================================================
#  基础指标
# ============================================================

def ema(series, n):
    return series.ewm(span=n, adjust=False).mean()


def ma(series, n):
    return series.rolling(n).mean()


def calc_macd(close):
    diff = ema(close, 12) - ema(close, 26)
    dea = ema(diff, 9)
    macd = 2 * (diff - dea)
    return diff, dea, macd


def calc_cmf(high, low, close, volume, period=20):
    denom = (high - low).replace(0, np.nan)
    mfm = (2 * close - high - low) / denom
    mfm = mfm.fillna(0)
    mfv = mfm * volume
    with np.errstate(divide='ignore', invalid='ignore'):
        cmf = mfv.rolling(period).sum() / volume.rolling(period).sum()
    return cmf.fillna(0)


def calc_angle(ma_series):
    """计算均线角度序列（返回 Series）。"""
    prev = ma_series.shift(1).replace(0, np.nan)
    ratio = ma_series / prev - 1
    angle = np.arctan(ratio.fillna(0) * 100) * 180 / np.pi
    return angle


def safe_last(series):
    if series is None or len(series) == 0:
        return 0.0
    val = series.iloc[-1]
    return float(val) if not pd.isna(val) else 0.0


def calc_rsi(close, n=14):
    """计算RSI指标"""
    if close is None or len(close) < n + 1:
        n = len(close) if close is not None else 0
        return pd.Series([50.0] * n, index=close.index) if close is not None else None
    diff = close.diff()
    gain = diff.clip(lower=0)
    loss = -diff.clip(upper=0)
    avg_gain = gain.rolling(n).mean()
    avg_loss = loss.rolling(n).mean().replace(0, np.nan)
    rs = avg_gain / avg_loss
    rsi = 100 - 100 / (1 + rs)
    return rsi.fillna(50)


def calc_rating(total_score):
    """根据总分返回评级"""
    if total_score >= 90:
        return 'A+'
    elif total_score >= 80:
        return 'A'
    elif total_score >= 70:
        return 'B+'
    elif total_score >= 40:
        return 'B'
    elif total_score >= 50:
        return 'C'
    else:
        return 'D'

# ====== core/scoring/dimension6plus2.py ======
"""6+2 Fused Scoring Module — DEEPSEEK 6-dimension breakout framework
   + Sentiment + Sector Heat (pure pandas/numpy, zero QMT dependency).

     # | Dimension              | Weight
    ---|------------------------|--------
     1 | Breakout Validity      | 22
     2 | Trend Health           | 13
     3 | Consolidation Strength | 20
     4 | Volume-Price Health    | 12
     5 | MACD Momentum          | 12
     6 | Valuation Safety       |  7
     7 | Sentiment              |  7
     8 | Sector Heat            |  7
       | **Total**              | 100
"""

import json
import warnings

import numpy as np
import pandas as pd



class ScoreCalculator6Plus2:
    """6+2 fused scorer. Pure calculation — no QMT/xtquant dependency."""

    def __init__(self, sector_heat_path="D:/QMT_POOL/sector_heat.json"):
        self._heat_map = {}
        self._load_sector_heat(sector_heat_path)

    # ------------------------------------------------------------
    # Sector heat loading (same pattern as ScoreCalculator8D)
    # ------------------------------------------------------------
    def _load_sector_heat(self, path):
        try:
            with open(path, "r", encoding="utf-8") as f:
                raw = f.read()
            data = json.loads(raw)
            if isinstance(data, dict):
                raw_map = data.get("stock_heat", data)
            else:
                raw_map = {}
            if not isinstance(raw_map, dict):
                raw_map = {}
            # 自动缩放：排名加分(1-10) → 百分比(10-100)
            values = [v for v in raw_map.values() if isinstance(v, (int, float))]
            scale = 1.0
            if values and max(values) <= 10:
                scale = 10.0
            self._heat_map = {k: float(v) * scale for k, v in raw_map.items()}
        except Exception:
            self._heat_map = {}

    def update_sector_bonus(self, bonus_map):
        """动态注入板块热度（运行时更新，覆盖文件加载）。

        bonus_map 中的值可能是排名加分 (1-10) 或百分比 (0-100)。
        自动检测并缩放到 0-100 范围。
        """
        if not bonus_map:
            return
        values = [v for v in bonus_map.values() if isinstance(v, (int, float))]
        scale = 1.0
        if values:
            max_v = max(values)
            if max_v <= 10:
                scale = 10.0
        for code, heat in bonus_map.items():
            scaled = float(heat) * scale
            clean = code.replace('.SZ','').replace('.SH','').replace('.BJ','')
            self._heat_map[code] = scaled
            self._heat_map[clean] = scaled

    # ------------------------------------------------------------
    # Public API
    # ------------------------------------------------------------
    def score_pool(
        self,
        pool_dict,
        fundamentals=None,
    ):
        """Score an entire pool cross-sectionally.

        Returns DataFrame indexed by stock_code with columns:
          [score_breakout, score_trend, score_consolidation, score_volumeprice,
           score_macd, score_valuation, score_sentiment, score_sector, score_total]
        """
        if not pool_dict:
            columns = [
                "score_breakout", "score_trend", "score_consolidation",
                "score_volumeprice", "score_macd", "score_valuation",
                "score_sentiment", "score_sector", "score_total",
            ]
            return pd.DataFrame(index=pd.Index([], name="stock_code"), columns=columns)

        # ---- Pass 1: compute 6 core dimensions + 5d return per stock ----
        records = {}
        fund = fundamentals or {}

        for code, df in pool_dict.items():
            if df is None or len(df) < 1:
                continue

            n = len(df)
            if n < 30:
                warnings.warn(f"[dimension6plus2] {code} has only {n} bars (< 30) — scoring with limited data")

            rec = self._score_core_dimensions(code, df, fund.get(code))

            # Collect 5-day return for cross-sectional sentiment
            rec["_ret_5d"] = self._compute_5d_return(df)
            records[code] = rec

        if not records:
            columns = [
                "score_breakout", "score_trend", "score_consolidation",
                "score_volumeprice", "score_macd", "score_valuation",
                "score_sentiment", "score_sector", "score_total",
            ]
            return pd.DataFrame(index=pd.Index([], name="stock_code"), columns=columns)

        # ---- Pass 2: cross-sectional sentiment ----
        ret_series = pd.Series(
            {code: rec["_ret_5d"] for code, rec in records.items()}
        ).dropna()
        sentiment_scores = self._compute_sentiment_scores(ret_series)

        # ---- Pass 3: sector heat lookup ----
        sector_scores = {}
        for code in records:
            clean = code.replace(".SZ", "").replace(".SH", "").replace(".BJ", "")
            heat = self._heat_map.get(code, self._heat_map.get(clean, None))
            if heat is None:
                sector_scores[code] = 3.5
            else:
                sector_scores[code] = 7.0 * max(0.0, min(100.0, float(heat))) / 100.0

        # ---- Assemble result ----
        rows = []
        for code, rec in records.items():
            rows.append(
                {
                    "stock_code": code,
                    "score_breakout": rec["score_breakout"],
                    "score_trend": rec["score_trend"],
                    "score_consolidation": rec["score_consolidation"],
                    "score_volumeprice": rec["score_volumeprice"],
                    "score_macd": rec["score_macd"],
                    "score_valuation": rec["score_valuation"],
                    "score_sentiment": sentiment_scores.get(code, 3.5),
                    "score_sector": sector_scores.get(code, 3.5),
                }
            )

        result = pd.DataFrame(rows)
        result["score_total"] = (
            result["score_breakout"]
            + result["score_trend"]
            + result["score_consolidation"]
            + result["score_volumeprice"]
            + result["score_macd"]
            + result["score_valuation"]
            + result["score_sentiment"]
            + result["score_sector"]
        )
        return result.set_index("stock_code")

    def score_single(
        self,
        stock_code,
        df,
        dynamic_pe=None,
        static_pe=None,
        pool_5d_returns=None,
    ):
        """Score a single stock.

        If pool_5d_returns is provided, sentiment is computed from it;
        otherwise sentiment defaults to 3.5 (neutral).
        """
        fund = {}
        if dynamic_pe is not None:
            fund["dynamic_pe"] = dynamic_pe
        if static_pe is not None:
            fund["static_pe"] = static_pe

        rec = self._score_core_dimensions(stock_code, df, fund)

        # Sentiment
        if pool_5d_returns is not None and stock_code in pool_5d_returns.index:
            sret = pool_5d_returns.loc[stock_code]
            if pd.notna(sret):
                sentiment_map = self._compute_sentiment_scores(pool_5d_returns.dropna())
                rec["score_sentiment"] = sentiment_map.get(stock_code, 3.5)
            else:
                rec["score_sentiment"] = 3.5
        else:
            rec["score_sentiment"] = 3.5

        # Sector heat
        clean = stock_code.replace(".SZ", "").replace(".SH", "").replace(".BJ", "")
        heat = self._heat_map.get(stock_code, self._heat_map.get(clean, None))
        if heat is None:
            rec["score_sector"] = 3.5
        else:
            rec["score_sector"] = 7.0 * max(0.0, min(100.0, float(heat))) / 100.0

        rec["score_total"] = (
            rec["score_breakout"]
            + rec["score_trend"]
            + rec["score_consolidation"]
            + rec["score_volumeprice"]
            + rec["score_macd"]
            + rec["score_valuation"]
            + rec["score_sentiment"]
            + rec["score_sector"]
        )
        return rec

    # ------------------------------------------------------------
    # Internal scoring helpers
    # ------------------------------------------------------------
    @staticmethod
    def _compute_5d_return(df):
        if len(df) < 7:
            return float("nan")
        return float(df["close"].iloc[-1] / df["close"].iloc[-6] - 1)

    @staticmethod
    def _score_breakout(df):
        """Dimension 1: Breakout Validity (22分)."""
        if len(df) < 21:
            return 0.0

        high = df["high"]
        low = df["low"]
        close = df["close"]
        volume = df["volume"]

        resistance = high.rolling(20).max().shift(1)
        amplitude_20 = high.rolling(20).max() / low.rolling(20).min() - 1

        amp_last = safe_last(amplitude_20)
        is_dense = amp_last <= 0.20

        res_last = safe_last(resistance)
        close_last = safe_last(close)
        if res_last <= 0.0:
            return 0.0
        breakout_pct = (close_last - res_last) / res_last * 100.0
        is_breakout = breakout_pct > 0.0

        vol_ma5 = volume.rolling(5).mean()
        vol_ratio = safe_last(volume) / safe_last(vol_ma5) if safe_last(vol_ma5) > 0 else 0.0

        if is_breakout and is_dense:
            base = 15.0
        elif is_breakout and not is_dense:
            base = 8.0
        else:
            base = 0.0

        if vol_ratio >= 2.0:
            vol_bonus = 7.0
        elif vol_ratio >= 1.2:
            vol_bonus = 4.0
        else:
            vol_bonus = 0.0

        return min(base + vol_bonus, 22.0)

    @staticmethod
    def _score_trend(df):
        """Dimension 2: Trend Health (13分)."""
        if len(df) < 6:
            return 0.0

        close = df["close"]
        ma5 = ma(close, 5)
        bias_5 = calc_bias(safe_last(close), safe_last(ma5))

        if 0.0 < bias_5 <= 12.0:
            return 13.0
        elif 12.0 < bias_5 <= 15.0:
            return 7.0
        else:
            return 0.0

    @staticmethod
    def _score_consolidation(df):
        """Dimension 3: Consolidation Strength (20分).

        For each of the last 5 trading days, check if low >= ma5 * 0.998.
        ma5 is computed per-day.
        """
        if len(df) < 5:
            return 0.0

        close = df["close"]
        low = df["low"]
        ma5 = ma(close, 5)

        # Use last 5 rows
        n_available = min(5, len(df))
        hold_days = 0
        for i in range(-n_available, 0):
            threshold = ma5.iloc[i] * 0.998
            if pd.notna(threshold) and low.iloc[i] >= threshold:
                hold_days += 1

        if n_available < 5:
            # Scale proportionally
            hold_days = int(round(hold_days * 5.0 / n_available))

        if hold_days >= 5:
            return 20.0
        elif hold_days == 4:
            return 15.0
        elif hold_days == 3:
            return 10.0
        else:
            return 0.0

    @staticmethod
    def _score_volume_price(df):
        """Dimension 4: Volume-Price Health (12分)."""
        if len(df) < 6:
            return 0.0

        volume = df["volume"]
        vol_ma5 = volume.rolling(5).mean()
        vol_ratio = safe_last(volume) / safe_last(vol_ma5) if safe_last(vol_ma5) > 0 else 0.0

        if vol_ratio <= 1.5:
            return 12.0
        elif vol_ratio <= 2.5:
            # Linear decay from 12 to 0
            return 12.0 * (2.5 - vol_ratio) / 1.0
        else:
            return 0.0

    @staticmethod
    def _score_macd(df):
        """Dimension 5: MACD Momentum (12分)."""
        if len(df) < 27:
            return 0.0

        close = df["close"]
        _, _, macd = calc_macd(close)

        macd_today = safe_last(macd)
        macd_yesterday = macd.iloc[-2] if len(macd) >= 2 else 0.0
        if pd.isna(macd_yesterday):
            macd_yesterday = 0.0

        if macd_today >= macd_yesterday:
            return 12.0
        else:
            if macd_today > 0 and macd_yesterday > 0:
                return 6.0
            elif macd_today > 0 and macd_yesterday <= 0:
                return 9.0
            elif macd_today <= 0 and macd_yesterday > 0:
                return 3.0
            else:
                return 0.0

    @staticmethod
    def _score_valuation(
        dynamic_pe,
        static_pe,
    ):
        """Dimension 6: Valuation Safety (7分)."""
        if dynamic_pe is None or static_pe is None or dynamic_pe <= 0.0 or static_pe <= 0.0:
            return 3.5
        if dynamic_pe <= static_pe:
            return 7.0
        ratio = static_pe / dynamic_pe
        return 7.0 * max(0.0, ratio)

    def _score_core_dimensions(
        self,
        code,
        df,
        fund,
    ):
        """Compute dimensions 1-6 for a single stock."""
        dynamic_pe = None
        static_pe = None
        if fund:
            dynamic_pe = fund.get("dynamic_pe")
            static_pe = fund.get("static_pe")

        return {
            "score_breakout": self._score_breakout(df),
            "score_trend": self._score_trend(df),
            "score_consolidation": self._score_consolidation(df),
            "score_volumeprice": self._score_volume_price(df),
            "score_macd": self._score_macd(df),
            "score_valuation": self._score_valuation(dynamic_pe, static_pe),
        }

    @staticmethod
    def _compute_sentiment_scores(ret_5d):
        """Dimension 7: Sentiment (7分) — cross-sectional percentile mapping."""
        n = len(ret_5d)
        if n == 0:
            return {}
        if n == 1:
            return {ret_5d.index[0]: 7.0}

        ranked = ret_5d.sort_values(ascending=False)  # rank 0 = best
        scores = {}
        for i, code in enumerate(ranked.index):
            pctile = (n - 1 - i) / (n - 1) * 100.0  # 0 = worst, 100 = best
            if pctile >= 80.0:
                scores[code] = 7.0
            elif pctile <= 20.0:
                scores[code] = 0.0
            else:
                scores[code] = 7.0 * (pctile - 20.0) / 60.0
        return scores


class ScoreCalculator6Plus2Experimental(ScoreCalculator6Plus2):
    """Parameterized experimental 6+2 scorer for backtest comparison."""

    DEFAULT_PARAMS = {
        "breakout_dense_amp": 0.18,
        "breakout_min_pct": 0.3,
        "breakout_ideal_pct": 2.5,
        "breakout_hot_pct": 7.0,
        "breakout_min_close_pos": 0.6,
        "breakout_min_vol_ratio": 1.2,
        "breakout_hot_vol_ratio": 3.0,
        "trend_bias_full": 10.0,
        "trend_bias_max": 14.0,
        "volume_full_ratio": 1.8,
        "volume_zero_ratio": 3.0,
        "macd_hist_improve_days": 3,
    }

    def __init__(self, sector_heat_path="D:/QMT_POOL/sector_heat.json", params=None):
        super().__init__(sector_heat_path=sector_heat_path)
        self.params = dict(self.DEFAULT_PARAMS)
        if params:
            self.params.update(params)

    def _score_breakout(self, df):
        if len(df) < 21:
            return 0.0

        high = df["high"]
        low = df["low"]
        close = df["close"]
        volume = df["volume"]
        p = self.params

        resistance = high.rolling(20).max().shift(1)
        amplitude_20 = high.rolling(20).max() / low.rolling(20).min() - 1
        res_last = safe_last(resistance)
        close_last = safe_last(close)
        high_last = safe_last(high)
        low_last = safe_last(low)
        if res_last <= 0.0:
            return 0.0

        breakout_pct = (close_last - res_last) / res_last * 100.0
        if breakout_pct < p["breakout_min_pct"]:
            return 0.0

        amp_last = safe_last(amplitude_20)
        close_pos = (close_last - low_last) / (high_last - low_last) if high_last > low_last else 0.5
        vol_ma5 = volume.rolling(5).mean()
        vol_ma_last = safe_last(vol_ma5)
        vol_ratio = safe_last(volume) / vol_ma_last if vol_ma_last > 0 else 0.0

        dense_score = 6.0 if amp_last <= p["breakout_dense_amp"] else 3.0
        pct_score = min(6.0, max(0.0, breakout_pct / p["breakout_ideal_pct"] * 6.0))
        if breakout_pct > p["breakout_hot_pct"]:
            pct_score *= 0.5
        pos_score = 4.0 if close_pos >= p["breakout_min_close_pos"] else 0.0
        if vol_ratio >= p["breakout_hot_vol_ratio"]:
            vol_score = 2.0
        elif vol_ratio >= p["breakout_min_vol_ratio"]:
            vol_score = 6.0
        else:
            vol_score = 0.0
        return min(dense_score + pct_score + pos_score + vol_score, 22.0)

    def _score_trend(self, df):
        if len(df) < 6:
            return 0.0

        close = df["close"]
        ma5 = ma(close, 5)
        bias_5 = calc_bias(safe_last(close), safe_last(ma5))
        p = self.params

        if 0.0 < bias_5 <= p["trend_bias_full"]:
            return 13.0
        if p["trend_bias_full"] < bias_5 <= p["trend_bias_max"]:
            return 7.0
        return 0.0

    def _score_volume_price(self, df):
        if len(df) < 6:
            return 0.0

        volume = df["volume"]
        vol_ma5 = volume.rolling(5).mean()
        vol_ma_last = safe_last(vol_ma5)
        vol_ratio = safe_last(volume) / vol_ma_last if vol_ma_last > 0 else 0.0
        p = self.params

        if vol_ratio <= p["volume_full_ratio"]:
            return 12.0
        if vol_ratio <= p["volume_zero_ratio"]:
            return 12.0 * (p["volume_zero_ratio"] - vol_ratio) / (p["volume_zero_ratio"] - p["volume_full_ratio"])
        return 0.0

    def _score_macd(self, df):
        if len(df) < 30:
            return 0.0

        close = df["close"]
        diff, dea, macd = calc_macd(close)
        p = self.params
        days = int(p["macd_hist_improve_days"])
        recent = macd.iloc[-days:]
        if len(recent) < days or recent.isna().any():
            return 0.0

        macd_today = safe_last(macd)
        macd_yesterday = macd.iloc[-2] if len(macd) >= 2 and pd.notna(macd.iloc[-2]) else 0.0
        diff_today = safe_last(diff)
        dea_today = safe_last(dea)
        improving = all(recent.iloc[i] >= recent.iloc[i - 1] for i in range(1, len(recent)))

        if macd_today > 0 and diff_today > dea_today and improving:
            return 12.0
        if macd_today > 0 and macd_today >= macd_yesterday:
            return 9.0
        if macd_today > 0:
            return 6.0
        if macd_today >= macd_yesterday:
            return 3.0
        return 0.0

# ====== core/signal_main_rise.py ======
"""8D打分系统 + 板块热度分析（纯逻辑，无 QMT 依赖）"""

import os
import re
import json
import math
import numpy as np
import pandas as pd
from datetime import datetime, timedelta



# ============================================================
#  参数常量
# ============================================================

REQUIRED_BARS = 120
MIN_BARS = 60
SECTOR_HOT_TOP_N = 10
MARKET_INDEX_CODE = '000001.SH'
MARKET_MA20 = 20
MARKET_MA60 = 60


# ============================================================
#  8D 加权打分系统
# ============================================================

class ScoreCalculator8D:
    """
    8维加权打分系统
    权重: 基本面18% 估值12% 技术面18% 资金面15% 成长性15% 情绪面8% 风险7% 板块7%
    """

    ROE_TARGET = 15.0
    GM_TARGET = 70.0
    DEBT_RATIO_SAFE = 30.0
    DEBT_RATIO_MAX = 65.0
    # 2026-06: PE/PB放宽以适配当前A股整体偏高估值环境，避免因估值维度一刀切筛掉成长股
    PE_CENTER = 25.0
    PE_WIDTH = 30.0
    PB_CENTER = 3.0
    PB_WIDTH = 3.0
    CAP_CENTER = 80.0
    CAP_WIDTH = 70.0
    BIAS_CENTER = 4.0
    BIAS_WIDTH = 3.0
    POS60_CENTER = 65.0
    POS60_WIDTH = 30.0
    PCT_CHG_CENTER = 3.0
    PCT_CHG_WIDTH = 3.5
    TURNOVER_CENTER = 5.0
    TURNOVER_WIDTH = 4.0
    AMP_CENTER = 5.0
    AMP_WIDTH = 3.0
    AMP_RISK_LOW = 3.0
    AMP_RISK_HIGH = 10.0
    SHRINK_LOW = 0.5
    SHRINK_HIGH = 1.0
    POS60_RISK_LOW = 70.0
    POS60_RISK_HIGH = 95.0
    BIAS_RISK_LOW = 6.0
    BIAS_RISK_HIGH = 14.0
    LIMIT_UP_THRESHOLD = 0.095

    def __init__(self, C=None):
        self.C = C
        self._financial_cache = {}
        self._sector_bonus = {}
        self._instrument_cache = {}

    @staticmethod
    def _linear_map(val, low, high, score_low, score_high, cap=True):
        """线性映射: 将 val 从 [low, high] 映射到 [score_low, score_high]"""
        if val <= low:
            return float(score_low)
        if val >= high:
            return float(score_high) if cap else float(score_high + (val - high) / (high - low) * (score_high - score_low))
        ratio = (val - low) / (high - low)
        return float(score_low + ratio * (score_high - score_low))

    @staticmethod
    def _bell_map(val, center, width, score_max, score_min=0):
        """钟形映射: 越接近 center 得分越高"""
        dist = abs(val - center)
        if dist >= width:
            return float(score_min)
        ratio = 1 - dist / width
        return float(score_min + ratio * (score_max - score_min))

    @staticmethod
    def _sigmoid_map(val, center, steepness, score_min, score_max):
        """Sigmoid 映射: 在 center 附近平滑过渡"""
        try:
            ratio = 1 / (1 + math.exp(-steepness * (val - center)))
            return float(score_min + ratio * (score_max - score_min))
        except Exception:
            return float((score_min + score_max) / 2)

    def load_financial_data(self, stock_list):
        """批量加载财务数据到缓存。C 为 None 时跳过。"""
        if not self.C or not stock_list:
            return
        end = datetime.now().strftime('%Y%m%d')
        start = (datetime.now() - timedelta(days=730)).strftime('%Y%m%d')
        fields = [
            'ASHAREINCOME.operating_revenue',
            'ASHAREINCOME.operating_cost',
            'ASHAREINCOME.net_profit_incl_min_int_inc',
            'ASHAREBALANCESHEET.total_liabilities',
            'ASHAREBALANCESHEET.total_equity',
            'PERSHAREINDEX.du_return_on_equity',
            'PERSHAREINDEX.s_fa_eps_basic',
            'PERSHAREINDEX.gross_profit',
            'PERSHAREINDEX.gear_ratio',
        ]
        loaded = 0
        failed = 0
        for code in stock_list:
            try:
                df = self.C.get_financial_data(fields, [code], start, end, 'announce_time')
                if df is None or (isinstance(df, pd.DataFrame) and df.empty):
                    continue
                if isinstance(df, pd.Series):
                    self._cache_financial_series(code, df)
                elif isinstance(df, pd.DataFrame):
                    self._cache_financial_series(code, df.iloc[-1])
                loaded += 1
            except Exception as e:
                failed += 1
                if failed <= 3:
                    print("  [财务数据] %s 加载失败: %s" % (code, e))
                continue
        if loaded > 0:
            print("  [财务数据] 加载 %d/%d 只股票, %d 只失败" % (loaded, len(stock_list), failed))
        else:
            print("  [财务数据] 警告: 未加载到任何财务数据")

    def _cache_financial_series(self, code, series):
        """将单只股票的财务序列缓存为结构化字典"""
        try:
            def _g(k, default=0.0):
                v = series.get(k, default)
                if v is None or (isinstance(v, float) and (v != v)):
                    return default
                return float(v)
            revenue = _g('operating_revenue')
            cost = _g('operating_cost')
            net_profit = _g('net_profit_incl_min_int_inc')
            liabilities = _g('total_liabilities')
            equity = _g('total_equity')
            roe_raw = _g('du_return_on_equity')
            eps = _g('s_fa_eps_basic')
            gp_raw = _g('gross_profit')
            gr_raw = _g('gear_ratio')
            roe = roe_raw / 100.0 if roe_raw > 1 else roe_raw
            gross_margin = (revenue - cost) / revenue if revenue > 0 else 0.0
            if gross_margin == 0 and gp_raw > 0:
                gross_margin = gp_raw / 100.0 if gp_raw > 1 else gp_raw
            total_assets = liabilities + equity
            debt_ratio = liabilities / total_assets if total_assets > 0 else 0.0
            if debt_ratio == 0 and gr_raw > 0:
                debt_ratio = gr_raw / 100.0 if gr_raw > 1 else gr_raw
            self._financial_cache[code] = {
                'roe': roe, 'gross_margin': gross_margin,
                'net_profit': net_profit, 'debt_ratio': debt_ratio,
                'eps': eps, 'has_data': True,
            }
        except Exception as e:
            print('  [财务数据] %s 缓存异常: %s' % (code, e))
            self._financial_cache[code] = {'has_data': False}

    def update_sector_bonus(self, bonus_map):
        """更新板块加分映射"""
        if bonus_map:
            self._sector_bonus = bonus_map

    def load_sector_heat_from_file(self, path='D:/QMT_POOL/sector_heat.json'):
        """从JSON文件加载板块热度数据"""
        try:
            with open(path, 'r', encoding='utf-8') as f:
                raw = f.read()
            data = json.loads(raw)
            if isinstance(data, dict):
                heat_map = data.get('stock_heat', data)
            else:
                heat_map = {}
            if heat_map:
                self._sector_bonus = heat_map
                print('  [热度] 加载 %d 只股票的板块热度加分' % len(heat_map))
            else:
                print('  [热度] 热度数据为空')
        except Exception as e:
            print('  [热度] 读取热度数据失败: %s' % e)

    def _fundamental_score(self, code):
        """基本面打分（满分18分）: ROE、毛利率、净利润、负债率"""
        fin = self._financial_cache.get(code, {})
        if not fin.get('has_data'):
            return 9.0
        score = 0.0
        roe = fin.get('roe', 0) * 100
        score += self._linear_map(roe, 0, self.ROE_TARGET, 0, 6, cap=True)
        gm = fin.get('gross_margin', 0) * 100
        score += self._linear_map(gm, 0, self.GM_TARGET, 0, 5, cap=True)
        np_val = fin.get('net_profit', 0)
        if np_val > 0:
            score += 3.0
            if np_val > 1e8:
                score += 1.0
        elif np_val < 0:
            score += max(4.0 + np_val / abs(np_val) * 0.5, 0)
        else:
            score += 2.0
        dr = fin.get('debt_ratio', 0.5) * 100
        score += self._linear_map(dr, self.DEBT_RATIO_SAFE, self.DEBT_RATIO_MAX, 3, 0, cap=True)
        return round(min(score, 18.0), 2)

    def _fetch_tencent_pe_pb(self, stock_code):
        """通过腾讯接口获取实时PE/PB和流通市值"""
        if not stock_code:
            return
        if stock_code in self._instrument_cache and self._instrument_cache[stock_code].get('pe'):
            return
        try:
            import re as _re
            import urllib.request
            code = stock_code.replace('.SH', '').replace('.SZ', '').replace('.BJ', '')
            prefix = 'sh' if code.startswith(('6', '9')) else 'sz'
            url = 'https://qt.gtimg.cn/q=' + prefix + code
            req = urllib.request.Request(url)
            req.add_header('User-Agent', 'Mozilla/5.0')
            resp = urllib.request.urlopen(req, timeout=5)
            raw = resp.read().decode('gbk')
            vals = raw.split('"')[1].split('~')
            pe_ttm = float(vals[39]) if len(vals) > 39 and vals[39] else None
            pb = float(vals[46]) if len(vals) > 46 and vals[46] else None
            circ_str = vals[44] if len(vals) > 44 and vals[44] else None
            circ_value = None
            if circ_str:
                m = _re.match(r'([\d.]+)', circ_str)
                if m:
                    num = float(m.group(1))
                    if '亿' in circ_str:
                        circ_value = num * 1e8
                    elif '万' in circ_str:
                        circ_value = num * 1e4
                    else:
                        circ_value = num
            if pe_ttm or pb or circ_value:
                self._instrument_cache[stock_code] = {
                    'pe': pe_ttm, 'pb': pb, 'circ_value': circ_value,
                }
        except Exception:
            pass

    def _valuation_score(self, stock_code, df, circ_value=None):
        """估值打分（满分12分）: PE钟形、PB钟形、流通市值"""
        fin = self._financial_cache.get(stock_code, {})
        inst = self._instrument_cache.get(stock_code, {})
        close = df['close'].astype(float)
        c = safe_last(close)
        score = 0.0
        eps = fin.get('eps', 0)
        if not inst.get('pe'):
            self._fetch_tencent_pe_pb(stock_code)
            inst = self._instrument_cache.get(stock_code, {})
        pe_inst = inst.get('pe', 0)
        pe_val = None
        if eps > 0 and c > 0:
            pe_val = c / eps
        elif pe_inst and pe_inst > 0:
            pe_val = pe_inst
        if pe_val and pe_val > 0:
            score += self._bell_map(pe_val, self.PE_CENTER, self.PE_WIDTH, 5, 0)
        else:
            score += 1.0
        roe = fin.get('roe', 0)
        pb_inst = inst.get('pb', 0)
        pb_val = None
        if roe > 0 and eps > 0:
            bvps = eps / roe
            if bvps > 0 and c > 0:
                pb_val = c / bvps
        elif pb_inst and pb_inst > 0:
            pb_val = pb_inst
        if pb_val and pb_val > 0:
            score += self._bell_map(pb_val, self.PB_CENTER, self.PB_WIDTH, 4, 0)
        else:
            score += 2.0
        cv = circ_value if (circ_value is not None and circ_value > 0) else inst.get('circ_value', 0)
        cap = (cv / 1e8) if (cv is not None and cv > 0) else 0
        if cap > 0:
            score += self._bell_map(cap, self.CAP_CENTER, self.CAP_WIDTH, 3, 0.5)
        else:
            score += 1.8
        return round(min(score, 12.0), 2)

    def _technical_score(self, df):
        """技术面打分（满分18分）: 均线排列、MACD、RSI、KDJ、位置百分比、乖离率"""
        close = df['close'].astype(float)
        high = df['high'].astype(float)
        low = df['low'].astype(float)
        c = safe_last(close)
        m5 = safe_last(ma(close, 5))
        m10 = safe_last(ma(close, 10))
        m20 = safe_last(ma(close, 20))
        m60 = safe_last(ma(close, 60))
        score = 0.0
        if c > 0 and m5 > 0 and m10 > 0 and m20 > 0 and m60 > 0:
            if c > m5 > m10 > m20 > m60:
                base = 3.5
                gaps_ok = all([
                    1 <= (m5 - m10) / m10 * 100 <= 8,
                    1 <= (m10 - m20) / m20 * 100 <= 8,
                    1 <= (m20 - m60) / m60 * 100 <= 8,
                ])
                score += base + (2.5 if gaps_ok else 1.5)
            elif m5 > m10 > m20:
                score += self._linear_map((m5 - m20) / m20 * 100, 0, 5, 2, 5, cap=True)
            elif m5 > m10:
                score += self._linear_map((m5 - m10) / m10 * 100, 0, 3, 1, 2.5, cap=True)
            else:
                score += max(self._linear_map((m5 - m10) / m10 * 100, -2, 0, 0, 1), 0)
        else:
            score += 1.0
        dif, dea, macd_hist = calc_macd(close)
        d = safe_last(dif)
        de = safe_last(dea)
        mh = safe_last(macd_hist)
        if not np.isnan(d) and not np.isnan(de):
            if d > 0:
                score += 1.0
            if d > de:
                score += 1.0
            if mh > 0:
                score += 1.0
            if len(macd_hist) >= 2 and not pd.isna(macd_hist.iloc[-2]):
                if mh > float(macd_hist.iloc[-2]):
                    score += 1.0
        else:
            score += 1.5
        rsi_val = safe_last(calc_rsi(close))
        if not np.isnan(rsi_val):
            if 40 <= rsi_val <= 60:
                score += 2.0
            elif 60 < rsi_val <= 80:
                score += 2.5
            elif rsi_val > 80:
                score += 1.5
            elif 20 <= rsi_val < 40:
                score += 0.8
            else:
                score += 0.3
        else:
            score += 1.2
        k, d_kdj, j = calc_kdj(close, high, low)
        k_val = safe_last(k)
        d_val = safe_last(d_kdj)
        j_val = safe_last(j)
        if not np.isnan(k_val) and not np.isnan(d_val):
            if k_val > d_val:
                score += 0.8
            if 20 <= k_val <= 80:
                score += 0.5
            if j_val > 0:
                score += 0.7
        else:
            score += 0.8
        if len(close) >= 60:
            high_60 = close.iloc[-60:].max()
            low_60 = close.iloc[-60:].min()
            if high_60 > low_60:
                pos_pct = (c - low_60) / (high_60 - low_60) * 100
                score += self._bell_map(pos_pct, self.POS60_CENTER, self.POS60_WIDTH, 2, 0)
            else:
                score += 1.0
        else:
            score += 1.0
        if m20 > 0:
            bias = (c - m20) / m20 * 100
            score += self._bell_map(bias, self.BIAS_CENTER, self.BIAS_WIDTH, 1, 0)
        else:
            score += 0.5

        return round(min(score, 18.0), 2)

    def _capital_score(self, df):
        """资金面打分（满分15分）: 量比、涨幅"""
        close = df['close'].astype(float)
        volume = df['volume'].astype(float)
        open_ = df['open'].astype(float)
        c = safe_last(close)
        v = safe_last(volume)
        o = safe_last(open_)
        score = 0.0
        vm5 = safe_last(ma(volume, 5))
        if vm5 > 0:
            vr = v / vm5
            if vr <= 1.0:
                score += self._linear_map(vr, 0.3, 1.0, 0, 3)
            elif vr <= 2.0:
                score += self._linear_map(vr, 1.0, 2.0, 3, 5)
            elif vr <= 3.0:
                score += self._linear_map(vr, 2.0, 3.0, 5, 4)
            else:
                score += max(4 - (vr - 3.0), 1.5)
        else:
            score += 2.0
        if o > 0:
            pct_chg = (c - o) / o * 100
        elif len(close) >= 2:
            prev_c = safe_last(close.shift(1))
            pct_chg = (c - prev_c) / prev_c * 100 if prev_c > 0 else 0
        else:
            pct_chg = 0
        score += self._bell_map(pct_chg, self.PCT_CHG_CENTER, self.PCT_CHG_WIDTH, 5, 0.5)
        score += self._bell_map(pct_chg, 2.5, 5.0, 3, 0.5)
        if vm5 > 0:
            vr = v / vm5
            score += self._linear_map(vr, 0.5, 1.8, 0, 2, cap=True)
        else:
            score += 1.0
        return round(min(score, 15.0), 2)

    def _growth_score(self, code, df):
        """成长性打分（满分15分）: 净利润规模、量比"""
        fin = self._financial_cache.get(code, {})
        volume = df['volume'].astype(float)
        close = df['close'].astype(float)
        c = safe_last(close)
        v = safe_last(volume)
        score = 0.0
        if fin.get('has_data'):
            np_val = fin.get('net_profit', 0)
            if np_val > 1e7:
                score += self._linear_map(np_val / 1e8, 0, 5, 6, 10, cap=True)
            elif np_val > 0:
                score += 4.0
            else:
                score += 1.0
        else:
            score += 5.0
        if c > 0 and v > 0:
            vm5 = safe_last(ma(volume, 5))
            if vm5 > 0:
                vr = v / vm5
                score += self._bell_map(vr, 1.5, 1.0, 5, 0.5)
            else:
                score += 2.0
        else:
            score += 2.0
        return round(min(score, 15.0), 2)

    def _sentiment_score(self, df):
        """情绪面打分（满分8分）: 涨幅、振幅、量比"""
        close = df['close'].astype(float)
        high = df['high'].astype(float)
        low = df['low'].astype(float)
        open_ = df['open'].astype(float)
        volume = df['volume'].astype(float)
        c = safe_last(close)
        o = safe_last(open_)
        h = safe_last(high)
        l = safe_last(low)
        v = safe_last(volume)
        score = 0.0
        if o > 0:
            pct_chg = (c - o) / o * 100
        elif len(close) >= 2:
            prev_c = safe_last(close.shift(1))
            pct_chg = (c - prev_c) / prev_c * 100 if prev_c > 0 else 0
        else:
            pct_chg = 0
        score += self._bell_map(pct_chg, self.PCT_CHG_CENTER, self.PCT_CHG_WIDTH, 3, 0.2)
        if o > 0:
            amp = (h - l) / o * 100
            score += self._bell_map(amp, self.AMP_CENTER, self.AMP_WIDTH, 3, 0.2)
        vm5 = safe_last(ma(volume, 5))
        if vm5 > 0 and v > 0:
            vr = v / vm5
            score += self._bell_map(vr, 1.5, 1.0, 2, 0.2)
        else:
            score += 0.8
        return round(min(score, 8.0), 2)

    def _risk_score(self, df):
        """风险打分（满分7分，初始10分扣减）: 振幅、缩量、高位位置、乖离率"""
        close = df['close'].astype(float)
        high = df['high'].astype(float)
        low = df['low'].astype(float)
        open_ = df['open'].astype(float)
        volume = df['volume'].astype(float)
        c = safe_last(close)
        o = safe_last(open_)
        h = safe_last(high)
        l = safe_last(low)
        v = safe_last(volume)
        m20 = safe_last(ma(close, 20))
        score = 10.0
        if o > 0:
            amp = (h - l) / o * 100
            score -= self._linear_map(amp, self.AMP_RISK_LOW, self.AMP_RISK_HIGH, 0, 2, cap=True)
        else:
            score -= 1.0
        prev_v = safe_last(volume.shift(1)) if len(volume) >= 2 else 0
        if prev_v > 0 and v > 0:
            vol_shrink = v / prev_v
            if vol_shrink < 0.7:
                score -= self._linear_map(vol_shrink, 0.3, 0.7, 2, 0, cap=True)
        else:
            score -= 0.5
        if len(close) >= 60:
            high_60 = close.iloc[-60:].max()
            low_60 = close.iloc[-60:].min()
            if high_60 > low_60:
                pos_pct = (c - low_60) / (high_60 - low_60) * 100
                score -= self._linear_map(pos_pct, self.POS60_RISK_LOW, self.POS60_RISK_HIGH, 0, 2, cap=True)
        else:
            score -= 0.5
        if m20 > 0:
            bias = abs((c - m20) / m20 * 100)
            score -= self._linear_map(bias, self.BIAS_RISK_LOW, self.BIAS_RISK_HIGH, 0, 1, cap=True)
        else:
            score -= 0.3
        return round(min(max(score - 3.0, 0), 7.0), 2)

    def _sector_score(self, stock_code, df):
        """板块打分（满分7分）: 量比、振幅、涨停强度、板块热度加分"""
        close = df['close'].astype(float)
        high = df['high'].astype(float)
        low = df['low'].astype(float)
        open_ = df['open'].astype(float)
        volume = df['volume'].astype(float)
        c = safe_last(close)
        o = safe_last(open_)
        h = safe_last(high)
        l = safe_last(low)
        v = safe_last(volume)
        score = 0.0
        vm5 = safe_last(ma(volume, 5))
        if vm5 > 0 and v > 0:
            vr = v / vm5
            score += self._bell_map(vr, 1.8, 1.2, 2, 0.2)
        else:
            score += 0.8
        if o > 0:
            amp = (h - l) / o * 100
            score += self._bell_map(amp, 4.0, 3.0, 1, 0.1)
        if o > 0:
            pct_chg = (c - o) / o * 100
            if pct_chg >= 9.5:
                score += 2.0
            elif pct_chg >= 7.0:
                score += 1.5
            elif pct_chg >= 5.0:
                score += 1.0
            elif pct_chg >= 3.0:
                score += 0.5
        else:
            score += 0.5
        bonus = self._sector_bonus.get(stock_code, 0)
        if bonus > 0:
            # 板块热度映射：0-10分映射为 0.0-2.0 附加分
            # 热力 6+（top 20%）  → 1.2-2.0
            # 热力 1-5（中间 40%） → 0.2-1.2
            # 热力 0（底部 40%）  → 不加分
            score += self._linear_map(bonus, 0, 10, 0.0, 2.0, cap=True)
        else:
            score += 1.0
        return round(min(score, 7.0), 2)

    @staticmethod
    def calc_market_coeff(index_close, index_ma20, index_ma60):
        """计算市场系数: 多头排列1.0, 震荡0.85, 空头0.60"""
        if pd.isna(index_close) or pd.isna(index_ma20) or pd.isna(index_ma60):
            return 1.0
        if index_close > index_ma20 > index_ma60:
            return 1.0
        elif index_close > index_ma20 or (index_ma60 is not None and index_close > index_ma60):
            return 0.85
        else:
            return 0.60

    def total_score(self, df, stock_code=None, circ_value=None,
                    index_close=None, index_ma20=None, index_ma60=None):
        """8D总分汇总: 加权各维度得分，返回字典"""
        s1 = self._fundamental_score(stock_code) if stock_code else 9.0
        s2 = self._valuation_score(stock_code, df, circ_value) if stock_code else 6.0
        s3 = self._technical_score(df)
        s4 = self._capital_score(df)
        s5 = self._growth_score(stock_code, df) if stock_code else 7.5
        s6 = self._sentiment_score(df)
        s7 = self._risk_score(df)
        s8 = self._sector_score(stock_code, df) if stock_code else 3.5
        scores = [s1, s2, s3, s4, s5, s6, s7, s8]
        for i in range(len(scores)):
            if np.isnan(scores[i]):
                scores[i] = 0.0
        s1, s2, s3, s4, s5, s6, s7, s8 = scores
        raw_total = round(s1 + s2 + s3 + s4 + s5 + s6 + s7 + s8, 2)
        coeff = self.calc_market_coeff(index_close, index_ma20, index_ma60)
        final_total = round(raw_total * coeff, 2)
        return {
            '基本面': s1, '估值面': s2, '技术面': s3, '资金面': s4,
            '成长面': s5, '情绪面': s6, '风险面': s7, '板块面': s8,
            'raw_total': raw_total, 'final_total': final_total,
            'market_coeff': coeff, 'rating': calc_rating(final_total),
        }


# ============================================================
#  板块热度（纯逻辑，仅文件加载，无 QMT API 调用）
# ============================================================

class SectorAnalyzer:
    """
    板块热度分析。
    仅支持从预计算文件加载；QMT API 调用由 adapter 层处理。
    """

    SECTOR_HEAT_FILE = 'D:/QMT_POOL/sector_heat.json'

    def __init__(self):
        self._bonus_cache = None
        self._cache_date = None

    def load_from_file(self, dt=None):
        """
        从预计算文件加载板块热度数据。
        支持两种格式:
          1. 富格式: {"update_date": "20260611", "stock_heat": {...}, "sector_rank": [...]}
          2. 扁平格式: {"000001.SZ": 10, "600036.SH": 8, ...}
        返回: {stock_code: bonus_score, ...} 或 None（文件不存在）
        """
        if not os.path.exists(self.SECTOR_HEAT_FILE):
            return None

        try:
            with open(self.SECTOR_HEAT_FILE, 'r', encoding='utf-8') as f:
                data = json.load(f)

            if not isinstance(data, dict) or len(data) == 0:
                return None

            # 检测格式：富格式有 'stock_heat' 键，扁平格式顶层就是股票代码
            today = dt.strftime('%Y%m%d') if dt else datetime.now().strftime('%Y%m%d')
            stock_heat = None
            sector_rank = []

            if 'stock_heat' in data:
                file_date = data.get('update_date', '')
                if file_date != today:
                    return None
                stock_heat = data.get('stock_heat', {})
                sector_rank = data.get('sector_rank', [])
                print("  [板块] 从文件加载 %d 只股票的板块热度（富格式，日期=%s）" % (len(stock_heat), file_date))
            else:
                # 检测是否为扁平格式：多数顶层 key 匹配股票代码格式
                code_pattern = re.compile(r'^\d{6}\.(SZ|SH|BJ)$')
                code_keys = [k for k in data.keys() if isinstance(k, str) and code_pattern.match(k)]
                if len(code_keys) > len(data) * 0.5:
                    stock_heat = data
                    mtime = os.path.getmtime(self.SECTOR_HEAT_FILE)
                    mtime_str = datetime.fromtimestamp(mtime).strftime('%Y%m%d')
                    print("  [板块] 从文件加载 %d 只股票的板块热度（扁平格式，文件时间=%s）" % (len(stock_heat), mtime_str))
                else:
                    return None

            if not stock_heat:
                return None

            if sector_rank:
                print("  热门板块前5:")
                for sec in sector_rank[:5]:
                    print("    %s. %s %+.2f%%  涨%d跌%d" % (
                        sec['rank'], sec['name'], sec['pct'],
                        sec['up_count'], sec['down_count']
                    ))

            self._bonus_cache = stock_heat
            self._cache_date = today
            return stock_heat

        except Exception:
            return None

    def calc_top10(self, force_refresh=False, dt=None):
        """
        计算前10热门板块的股票加分映射。
        仅支持从文件加载（QMT API 版本在 adapter 层）。
        """
        today = dt.strftime('%Y%m%d') if dt else datetime.now().strftime('%Y%m%d')
        if self._bonus_cache is not None and self._cache_date == today and not force_refresh:
            return self._bonus_cache

        print("  [板块] 尝试从文件加载板块热度...")
        file_result = self.load_from_file(dt=dt)
        if file_result is not None:
            return file_result

        print("  [板块] 无板块数据文件，返回空")
        self._bonus_cache = {}
        self._cache_date = today
        return {}


